#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <cuda_runtime.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define CUDA_CHECK(call)                                                      \
	do {                                                                      \
		cudaError_t err__ = (call);                                           \
		if (err__ != cudaSuccess) {                                           \
			fprintf(stderr, "CUDA error: %s\n", cudaGetErrorString(err__));   \
			exit(1);                                                          \
		}                                                                     \
	} while (0)

__global__ static void srad_kernel_1(
	const float *J,
	float *dN,
	float *dS,
	float *dW,
	float *dE,
	float *c,
	int rows,
	int cols,
	float q0sqr)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;

		int iN = (i == 0) ? 0 : (i - 1);
		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jW = (j == 0) ? 0 : (j - 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float Jc = J[k];

		float dNk = J[iN * cols + j] - Jc;
		float dSk = J[iS * cols + j] - Jc;
		float dWk = J[i * cols + jW] - Jc;
		float dEk = J[i * cols + jE] - Jc;

		dN[k] = dNk;
		dS[k] = dSk;
		dW[k] = dWk;
		dE[k] = dEk;

		float G2 = (dNk * dNk + dSk * dSk + dWk * dWk + dEk * dEk) / (Jc * Jc);
		float L = (dNk + dSk + dWk + dEk) / Jc;

		float num = (0.5f * G2) - (0.0625f * (L * L));
		float den = 1.0f + (0.25f * L);
		float qsqr = num / (den * den);

		den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
		float ck = 1.0f / (1.0f + den);

		if (ck < 0.0f) ck = 0.0f;
		else if (ck > 1.0f) ck = 1.0f;

		c[k] = ck;
	}
}

__global__ static void srad_kernel_2(
	float *J,
	const float *c,
	const float *dN,
	const float *dS,
	const float *dW,
	const float *dE,
	int rows,
	int cols,
	float lambda)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;

		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float cN = c[k];
		float cS = c[iS * cols + j];
		float cW = c[k];
		float cE = c[i * cols + jE];

		float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

		J[k] = J[k] + 0.25f * lambda * D;
	}
}

extern "C" void srad_cuda(float *h_J, int rows, int cols, int r1, int r2, int c1, int c2, float lambda, int niter)
{
	int size_I = rows * cols;
	int size_R = (r2 - r1 + 1) * (c2 - c1 + 1);
	size_t bytes = (size_t)size_I * sizeof(float);

	float *d_J = NULL;
	float *d_c = NULL;
	float *dN = NULL;
	float *dS = NULL;
	float *dW = NULL;
	float *dE = NULL;

	CUDA_CHECK(cudaMalloc((void **)&d_J, bytes));
	CUDA_CHECK(cudaMalloc((void **)&d_c, bytes));
	CUDA_CHECK(cudaMalloc((void **)&dN, bytes));
	CUDA_CHECK(cudaMalloc((void **)&dS, bytes));
	CUDA_CHECK(cudaMalloc((void **)&dW, bytes));
	CUDA_CHECK(cudaMalloc((void **)&dE, bytes));

	CUDA_CHECK(cudaMemcpy(d_J, h_J, bytes, cudaMemcpyHostToDevice));

	dim3 block(BLOCK_SIZE, BLOCK_SIZE);
	dim3 grid((cols + block.x - 1) / block.x, (rows + block.y - 1) / block.y);

	for (int iter = 0; iter < niter; iter++) {
		float sum = 0.0f;
		float sum2 = 0.0f;

		for (int i = r1; i <= r2; i++) {
			for (int j = c1; j <= c2; j++) {
				float tmp = h_J[i * cols + j];
				sum += tmp;
				sum2 += tmp * tmp;
			}
		}

		float meanROI = sum / size_R;
		float varROI = (sum2 / size_R) - meanROI * meanROI;
		float q0sqr = varROI / (meanROI * meanROI);

		srad_kernel_1<<<grid, block>>>(d_J, dN, dS, dW, dE, d_c, rows, cols, q0sqr);
		CUDA_CHECK(cudaGetLastError());

		srad_kernel_2<<<grid, block>>>(d_J, d_c, dN, dS, dW, dE, rows, cols, lambda);
		CUDA_CHECK(cudaGetLastError());

		CUDA_CHECK(cudaDeviceSynchronize());
		CUDA_CHECK(cudaMemcpy(h_J, d_J, bytes, cudaMemcpyDeviceToHost));
	}

	CUDA_CHECK(cudaFree(d_J));
	CUDA_CHECK(cudaFree(d_c));
	CUDA_CHECK(cudaFree(dN));
	CUDA_CHECK(cudaFree(dS));
	CUDA_CHECK(cudaFree(dW));
	CUDA_CHECK(cudaFree(dE));
}
